compliant:
// Use default certificate validation
var client = new HttpClient();
var response = await client.GetAsync("https://api.example.com");

// Custom validation with proper checks
var handler = new HttpClientHandler();
handler.ServerCertificateCustomValidationCallback = (message, cert, chain, errors) =>
{
    return errors == SslPolicyErrors.None && 
           cert.Subject.Contains("CN=api.example.com");
};
var client = new HttpClient(handler);

// Using certificate pinning
var handler = new HttpClientHandler();
handler.ServerCertificateCustomValidationCallback = (message, cert, chain, errors) =>
{
    var expectedThumbprint = "1234567890ABCDEF";
    return cert.GetCertHashString() == expectedThumbprint;
};
